import React, { useState, useEffect } from "react";
import { LANGUAGES } from "../../constants";
import "./SupportPage.css";
import { MainLayout } from "../../layouts";

const faqData = [
  {
    id: 1,
    category: "account",
    q: {
      vi: "Làm sao để tạo tài khoản?",
      en: "How do I create an account?",
    },
    a: {
      vi: "Nhấp vào Đăng ký, điền thông tin và xác nhận email để kích hoạt.",
      en: "Click Register, fill in the form and verify your email to activate.",
    },
  },
  {
    id: 2,
    category: "jobs",
    q: {
      vi: "Tôi có thể ứng tuyển bao nhiêu công việc?",
      en: "How many jobs can I apply for?",
    },
    a: {
      vi: "Không giới hạn số lượt ứng tuyển.",
      en: "You can apply to unlimited jobs.",
    },
  },
  {
    id: 3,
    category: "technical",
    q: {
      vi: "Trang không hiển thị đúng?",
      en: "Page not displaying properly?",
    },
    a: {
      vi: "Hãy thử làm mới trình duyệt hoặc xóa bộ nhớ cache.",
      en: "Try refreshing your browser or clearing cache.",
    },
  },
  {
    id: 4,
    category: "payment",
    q: { vi: "Thanh toán có an toàn không?", en: "Is payment secure?" },
    a: {
      vi: "Chúng tôi mã hóa giao dịch và không lưu trữ thông tin thẻ.",
      en: "We encrypt transactions and never store card details.",
    },
  },
];

const categories = [
  { key: "all", vi: "Tất cả", en: "All" },
  { key: "account", vi: "Tài khoản", en: "Account" },
  { key: "jobs", vi: "Công việc", en: "Jobs" },
  { key: "payment", vi: "Thanh toán", en: "Payment" },
  { key: "technical", vi: "Kỹ thuật", en: "Technical" },
];

const SupportPage = () => {
  const [language] = useState(localStorage.getItem("language") || LANGUAGES.VI);
  const [activeCategory, setActiveCategory] = useState("all");
  const [expanded, setExpanded] = useState(null);
  const [search, setSearch] = useState("");
  const [form, setForm] = useState({
    name: "",
    email: "",
    topic: "",
    message: "",
  });
  const [formErrors, setFormErrors] = useState({});
  const [submitting, setSubmitting] = useState(false);
  const [submitted, setSubmitted] = useState(false);

  const t = {
    vi: {
      title: "Hỗ trợ khách hàng",
      subtitle:
        "Tìm câu trả lời nhanh hoặc gửi yêu cầu đến đội ngũ của chúng tôi.",
      searchPlaceholder: "Tìm kiếm câu hỏi...",
      faqTitle: "Câu hỏi thường gặp",
      categories: "Danh mục",
      contactTitle: "Gửi yêu cầu",
      name: "Họ và tên",
      email: "Email",
      topic: "Chủ đề",
      message: "Nội dung",
      topicPlaceholder: "Chủ đề bạn cần hỗ trợ",
      messagePlaceholder: "Mô tả chi tiết vấn đề của bạn...",
      submit: "Gửi yêu cầu",
      submitting: "Đang gửi...",
      submitted: "Yêu cầu đã được gửi! Chúng tôi sẽ phản hồi sớm.",
      nameRequired: "Vui lòng nhập họ tên",
      emailRequired: "Vui lòng nhập email",
      emailInvalid: "Email không hợp lệ",
      topicRequired: "Vui lòng nhập chủ đề",
      messageRequired: "Vui lòng nhập nội dung",
      noResult: "Không tìm thấy câu hỏi phù hợp.",
      switchHint: "Chuyển ngôn ngữ",
      backHome: "Về trang chủ",
      stats: {
        response: "Phản hồi trung bình",
        tickets: "Vé đã xử lý",
        satisfaction: "Hài lòng",
        minutes: "phút",
      },
      channelsTitle: "Kênh hỗ trợ",
      liveChat: "Trò chuyện trực tiếp",
      liveChatDesc: "Kết nối với đội ngũ của chúng tôi trong vài phút",
      emailSupport: "Email hỗ trợ",
      emailSupportDesc: "Nhận phản hồi trong vòng 24h làm việc",
      phoneSupport: "Điện thoại",
      phoneSupportDesc: "Tư vấn nhanh trong giờ làm việc",
      knowledgeBase: "Trung tâm tài liệu",
      knowledgeBaseDesc: "Hướng dẫn chi tiết & mẹo sử dụng",
      startChat: "Bắt đầu chat",
      sendEmail: "Gửi email",
      callNow: "Gọi ngay",
      open: "Mở",
      resourcesTitle: "Tài nguyên nhanh",
      trendingTitle: "Chủ đề nổi bật",
      processTitle: "Quy trình hỗ trợ",
      steps: [
        { title: "Tìm kiếm trước", desc: "Nhập từ khóa để tìm câu trả lời tức thì." },
        { title: "Xem FAQ", desc: "Mở rộng các câu hỏi liên quan." },
        { title: "Gửi yêu cầu", desc: "Nếu chưa giải quyết, gửi biểu mẫu hỗ trợ." },
        { title: "Theo dõi", desc: "Kiểm tra email để nhận cập nhật tiến trình." },
      ],
    },
    en: {
      title: "Customer Support",
      subtitle: "Find quick answers or send a request to our team.",
      searchPlaceholder: "Search questions...",
      faqTitle: "Frequently Asked Questions",
      categories: "Categories",
      contactTitle: "Submit a Request",
      name: "Full Name",
      email: "Email",
      topic: "Topic",
      message: "Message",
      topicPlaceholder: "Topic you need help with",
      messagePlaceholder: "Describe your issue in detail...",
      submit: "Send Request",
      submitting: "Submitting...",
      submitted: "Your request has been sent! We'll respond shortly.",
      nameRequired: "Please enter name",
      emailRequired: "Please enter email",
      emailInvalid: "Invalid email",
      topicRequired: "Please enter a topic",
      messageRequired: "Please enter a message",
      noResult: "No matching questions found.",
      switchHint: "Switch language",
      backHome: "Back to Home",
      stats: {
        response: "Avg. Response",
        tickets: "Tickets Resolved",
        satisfaction: "Satisfaction",
        minutes: "mins",
      },
      channelsTitle: "Support Channels",
      liveChat: "Live Chat",
      liveChatDesc: "Connect with our team within minutes",
      emailSupport: "Email Support",
      emailSupportDesc: "Get a reply within 24 business hours",
      phoneSupport: "Phone",
      phoneSupportDesc: "Quick guidance during working hours",
      knowledgeBase: "Knowledge Base",
      knowledgeBaseDesc: "Detailed guides & usage tips",
      startChat: "Start Chat",
      sendEmail: "Send Email",
      callNow: "Call Now",
      open: "Open",
      resourcesTitle: "Quick Resources",
      trendingTitle: "Trending Topics",
      processTitle: "Support Process",
      steps: [
        { title: "Search First", desc: "Enter keywords for instant answers." },
        { title: "Check FAQs", desc: "Expand related common questions." },
        { title: "Submit Request", desc: "If unresolved, send a support form." },
        { title: "Follow Up", desc: "Watch email for progress updates." },
      ],
    },
  }[language];

  // Language switch now handled globally in Header (MainLayout). Keep local sync if needed.
  // This page reads language from localStorage on mount; Header controls updates.

  const filteredFaq = faqData.filter((item) => {
    const inCategory =
      activeCategory === "all" || item.category === activeCategory;
    const keyword = search.toLowerCase();
    const text = (item.q[language] + item.a[language]).toLowerCase();
    const matches = text.includes(keyword);
    return inCategory && (!keyword || matches);
  });

  const validate = () => {
    const errs = {};
    if (!form.name.trim()) errs.name = t.nameRequired;
    if (!form.email.trim()) errs.email = t.emailRequired;
    else if (!/\S+@\S+\.\S+/.test(form.email)) errs.email = t.emailInvalid;
    if (!form.topic.trim()) errs.topic = t.topicRequired;
    if (!form.message.trim()) errs.message = t.messageRequired;
    return errs;
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    const errs = validate();
    setFormErrors(errs);
    if (Object.keys(errs).length) return;
    setSubmitting(true);
    await new Promise((res) => setTimeout(res, 1500));
    setSubmitting(false);
    setSubmitted(true);
    setForm({ name: "", email: "", topic: "", message: "" });
    setTimeout(() => setSubmitted(false), 4000);
  };

  // Animated stats counters (simple incremental)
  const [resp, setResp] = useState(0); // target 2
  const [tickets, setTickets] = useState(0); // target 12500
  const [satis, setSatis] = useState(0); // target 97
  useEffect(() => {
    const animate = (target, setter, duration) => {
      const start = performance.now();
      const step = (now) => {
        const progress = Math.min(1, (now - start) / duration);
        setter(Math.round(target * progress));
        if (progress < 1) requestAnimationFrame(step);
      };
      requestAnimationFrame(step);
    };
    animate(2, setResp, 800);
    animate(12500, setTickets, 1200);
    animate(97, setSatis, 1000);
  }, [language]);

  const channels = [
    {
      key: "chat",
      icon: <i className="fas fa-comments"></i>,
      title: t.liveChat,
      desc: t.liveChatDesc,
      action: t.startChat,
      color: "#3b82f6",
    },
    {
      key: "email",
      icon: <i className="fas fa-envelope-open-text"></i>,
      title: t.emailSupport,
      desc: t.emailSupportDesc,
      action: t.sendEmail,
      color: "#10b981",
    },
    {
      key: "phone",
      icon: <i className="fas fa-phone-alt"></i>,
      title: t.phoneSupport,
      desc: t.phoneSupportDesc,
      action: t.callNow,
      color: "#f59e0b",
    },
    {
      key: "kb",
      icon: <i className="fas fa-book"></i>,
      title: t.knowledgeBase,
      desc: t.knowledgeBaseDesc,
      action: t.open,
      color: "#6366f1",
    },
  ];

  const trending = language === "vi"
    ? ["Tạo tài khoản", "Khôi phục mật khẩu", "Nâng cấp gói", "Thanh toán"]
    : ["Create account", "Reset password", "Upgrade plan", "Payment"];

  return (
    <MainLayout>
      <div className="support-page">
        <div className="support-hero">
          <div className="hero-overlay" />
          <div className="support-hero-content">
            <h1 className="support-title-gradient">{t.title}</h1>
            <p className="support-subtitle-text">{t.subtitle}</p>
            <div className="support-search-wrapper">
              <input
                type="text"
                placeholder={t.searchPlaceholder}
                value={search}
                onChange={(e) => setSearch(e.target.value)}
                className="support-search-input"
              />
            </div>
            <div className="category-pills">
              {categories.map((c) => (
                <button
                  key={c.key}
                  className={`pill ${activeCategory === c.key ? "active" : ""}`}
                  onClick={() => setActiveCategory(c.key)}
                >
                  {c[language]}
                </button>
              ))}
            </div>
          </div>
        </div>

        <main className="support-main">
          <div className="support-grid">
            <div className="support-left">
              {/* Stats & Channels */}
              <section className="overview-section">
                <div className="stats-cards">
                  <div className="stat-card">
                    <div className="stat-value">{resp}<span className="stat-suffix">{t.stats.minutes}</span></div>
                    <div className="stat-label">{t.stats.response}</div>
                  </div>
                  <div className="stat-card">
                    <div className="stat-value">{tickets.toLocaleString()}+</div>
                    <div className="stat-label">{t.stats.tickets}</div>
                  </div>
                    <div className="stat-card">
                    <div className="stat-value">{satis}%</div>
                    <div className="stat-label">{t.stats.satisfaction}</div>
                  </div>
                </div>
                <h3 className="channels-heading">
                  <span className="heading-accent">{t.channelsTitle}</span>
                </h3>
                <div className="channels-grid">
                  {channels.map((ch) => (
                    <div className="channel-card" key={ch.key} style={{ "--channel-color": ch.color }}>
                      <div className="channel-icon" aria-hidden="true">{ch.icon}</div>
                      <div className="channel-info">
                        <h4 className="channel-title">{ch.title}</h4>
                        <p className="channel-desc">{ch.desc}</p>
                        <button type="button" className="channel-action">{ch.action}</button>
                      </div>
                    </div>
                  ))}
                </div>
              </section>

              <section className="faq-section">
            <h2 className="section-title">{t.faqTitle}</h2>
            <div className="faq-list" role="list">
              {filteredFaq.length === 0 && (
                <div className="empty-state">{t.noResult}</div>
              )}
              {filteredFaq.map((item) => {
                const isOpen = expanded === item.id;
                return (
                  <div
                    key={item.id}
                    className={`faq-item ${isOpen ? "open" : ""}`}
                  >
                    <button
                      className="faq-question"
                      onClick={() => setExpanded(isOpen ? null : item.id)}
                      aria-expanded={isOpen}
                    >
                      <span>{item.q[language]}</span>
                      <span className="faq-icon" aria-hidden="true">
                        {isOpen ? "−" : "+"}
                      </span>
                    </button>
                    {isOpen && (
                      <div className="faq-answer" role="region">
                        <p>{item.a[language]}</p>
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
              </section>

              <section className="contact-section">
            <h2 className="section-title">{t.contactTitle}</h2>
            <form className="support-form" onSubmit={handleSubmit} noValidate>
              <div className="form-grid">
                <div className="form-group">
                  <label>{t.name}</label>
                  <input
                    type="text"
                    value={form.name}
                    onChange={(e) => setForm({ ...form, name: e.target.value })}
                    className={formErrors.name ? "error" : ""}
                  />
                  {formErrors.name && (
                    <span className="error-message">{formErrors.name}</span>
                  )}
                </div>
                <div className="form-group">
                  <label>{t.email}</label>
                  <input
                    type="email"
                    value={form.email}
                    onChange={(e) =>
                      setForm({ ...form, email: e.target.value })
                    }
                    className={formErrors.email ? "error" : ""}
                  />
                  {formErrors.email && (
                    <span className="error-message">{formErrors.email}</span>
                  )}
                </div>
                <div className="form-group">
                  <label>{t.topic}</label>
                  <input
                    type="text"
                    placeholder={t.topicPlaceholder}
                    value={form.topic}
                    onChange={(e) =>
                      setForm({ ...form, topic: e.target.value })
                    }
                    className={formErrors.topic ? "error" : ""}
                  />
                  {formErrors.topic && (
                    <span className="error-message">{formErrors.topic}</span>
                  )}
                </div>
                <div className="form-group full">
                  <label>{t.message}</label>
                  <textarea
                    rows={5}
                    placeholder={t.messagePlaceholder}
                    value={form.message}
                    onChange={(e) =>
                      setForm({ ...form, message: e.target.value })
                    }
                    className={formErrors.message ? "error" : ""}
                  />
                  {formErrors.message && (
                    <span className="error-message">{formErrors.message}</span>
                  )}
                </div>
              </div>
              <button
                type="submit"
                className={`support-submit ${submitting ? "loading" : ""}`}
                disabled={submitting}
              >
                {submitting ? t.submitting : t.submit}
              </button>
              {submitted && (
                <div className="submit-success" role="status">
                  {t.submitted}
                </div>
              )}
            </form>
              </section>
            </div>
            <aside className="support-right">
              <div className="resources-card">
                <h3 className="resources-title">{t.resourcesTitle}</h3>
                <div className="trending-block">
                  <h4 className="trending-title">{t.trendingTitle}</h4>
                  <div className="trending-tags">
                    {trending.map((tag) => (
                      <button
                        key={tag}
                        type="button"
                        className="trending-tag"
                        onClick={() => setSearch(tag)}
                      >
                        <i className="fas fa-hashtag"></i>{tag}
                      </button>
                    ))}
                  </div>
                </div>
                <div className="process-block">
                  <h4 className="process-title">{t.processTitle}</h4>
                  <ol className="process-steps">
                    {t.steps.map((s, idx) => (
                      <li key={idx} className="process-step">
                        <div className="step-index">{idx + 1}</div>
                        <div className="step-body">
                          <div className="step-title">{s.title}</div>
                          <div className="step-desc">{s.desc}</div>
                        </div>
                      </li>
                    ))}
                  </ol>
                </div>
              </div>
            </aside>
          </div>
        </main>
      </div>
    </MainLayout>
  );
};

export default SupportPage;
